void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    vec2 d = uTexSize.zw*6;
    float1 dx = ( GetBlur1(vUv+vec2(1,0)*d)-GetBlur1(vUv-vec2(1,0)*d) ).y;
    float1 dy = ( GetBlur1(vUv+vec2(0,1)*d)-GetBlur1(vUv-vec2(0,1)*d) ).y;
    vec2 uv_y = vUv-vec2(dx,dy)*0.6;

ret = mix(vec3(1.6,0.8,0)*texture(sampler_fc_main, uv_y).x,
                              vec3(0.5,-0.2,2), GetBlur1(vUv).y*0.35);


  fragColor = ret;
}
